277	/**
278	 * 從主 session 檔案中提取所有 agentId
279	 */
280	export async function extractAgentIds(
281	  sessionPath: string
282	): Promise<Set<string>> {
283	  const agentIds = new Set<string>();
284	
285	  try {
286	    const file = Bun.file(sessionPath);
287	    const content = await file.text();
288	    const lines = content.split('\n').filter(Boolean);
289	
290	    for (const line of lines) {
291	      try {
292	        const data = JSON.parse(line);
293	        // 從 toolUseResult 中提取 agentId，並驗證格式以防止路徑穿越
294	        const agentId = data.toolUseResult?.agentId;
295	        if (agentId && isValidAgentId(agentId)) {
296	          agentIds.add(agentId);
297	        }
298	      } catch {
299	        // 忽略解析錯誤
300	      }
301	    }
302	  } catch {
303	    // 忽略檔案讀取錯誤
304	  }
305	
306	  return agentIds;
307	}
308	
309	/**
310	 * 掃描 subagents 目錄，找出尚未被監控的新 subagent 檔案
311	 * @param subagentsDir subagents 目錄路徑
312	 * @param knownAgentIds 已知的 agentId 集合
313	 * @returns 新發現的 agentId 陣列
314	 */
315	export async function scanForNewSubagents(
316	  subagentsDir: string,
317	  knownAgentIds: Set<string>
318	): Promise<string[]> {
319	  const newAgentIds: string[] = [];
320	
321	  try {
322	    const glob = new Glob('agent-*.jsonl');
323	    for await (const file of glob.scan({ cwd: subagentsDir })) {
324	      // Defensive: skip anything under a subdirectory (e.g. nested
325	      // workflows/wf_*/agent-*.jsonl). Bun.Glob is non-recursive by
326	      // default but this guard protects against future behavior changes.
327	      if (file.includes('/')) continue;
328	      // 從檔名 "agent-{id}.jsonl" 提取 id（支援 7-40 位 hex）
329	      const match = file.match(/^agent-([0-9a-f]{7,40})\.jsonl$/i);
330	      if (match && match[1]) {
331	        const agentId = match[1];
332	        if (!knownAgentIds.has(agentId)) {
333	          newAgentIds.push(agentId);
334	        }
335	      }
336	    }
337	  } catch {
338	    // 目錄不存在或無法存取時靜默忽略
339	    // 這是預期行為：subagent 可能尚未建立目錄
340	  }
341	
342	  return newAgentIds;
343	}
344	
345	// ============================================================
346	// Core Functions
347	// ============================================================
348	
349	/**
350	 * 嘗試新增 subagent 檔案監控（含重試邏輯）
351	 *
352	 * @param subagentPath - subagent 檔案路徑
353	 * @param agentId - agent 識別碼
354	 * @param watcher - watcher 處理器
355	 * @param output - 輸出處理器
356	 * @param config - 重試配置
357	 * @returns Promise<boolean> 是否成功新增
358	 */
359	export async function tryAddSubagentFile(
360	  subagentPath: string,
361	  agentId: string,
362	  watcher: WatcherHandler,
363	  output: OutputHandler,
364	  config: RetryConfig = FALLBACK_DETECTION_RETRY,
365	  parentAgentId?: string
366	): Promise<boolean> {
367	  const doTry = async (retriesLeft: number): Promise<boolean> => {
368	    try {
369	      const file = Bun.file(subagentPath);
370	      if (await file.exists()) {
371	        await watcher.addFile({
372	          path: subagentPath,
373	          label: makeAgentLabel(agentId, parentAgentId),
374	        });
375	        return true;
376	      } else if (retriesLeft > 0) {
377	        await new Promise((resolve) => setTimeout(resolve, config.retryDelay));
378	        return doTry(retriesLeft - 1);
379	      } else {
380	        output.debug(`Subagent file not found after retries: ${agentId}`);
381	        return false;
382	      }
383	    } catch (error) {
384	      output.error(`Failed to add subagent watcher: ${agentId} - ${error}`);
385	      return false;
386	    }
387	  };
388	
389	  // 初始延遲後開始嘗試
390	  await new Promise((resolve) => setTimeout(resolve, config.initialDelay));
391	  return doTry(config.maxRetries);
392	}
393	
394	// ============================================================
395	// SubagentDetector Class
396	// ============================================================
397	
398	/**
399	 * Subagent 偵測器 - 整合 early detection 和 fallback detection
400	 */
401	export class SubagentDetector {
402	  private knownAgentIds: Set<string>;
403	  private config: SubagentDetectorConfig;
404	  private dirWatcher: FSWatcher | null = null;
405	  private parentWatcher: FSWatcher | null = null;
406	  private scanTimer: ReturnType<typeof setTimeout> | null = null;
407	  private isWatching = false;
408	  // 追蹤所有 pending 的 setTimeout 句柄，用於 stop() 時清除
409	  private pendingTimers: Set<ReturnType<typeof setTimeout>> = new Set();
410	  // subagents/ 目錄 retry 的指數退避計數（成功 attach 後重置）
411	  private dirRetryAttempts = 0;
412	  // FIFO queue: Task tool_use descriptions, matched to agents in registration order.
413	  // May mismatch with parallel Task launches (known limitation, wrong label only).
414	  private pendingDescriptions: string[] = [];
415	  // spawnRegistry: 紀錄每個 Agent tool_use id 由誰呼叫
416	  // value = parent agentId（巢狀）或 MAIN_SOURCE（主 session）
417	  // 用於 meta.json.toolUseId 反查 → 推導 nested subagent 的 parent
418	  private spawnRegistry: Map<string, string> = new Map();
419	
420	  constructor(initialAgentIds: Set<string>, config: SubagentDetectorConfig) {
421	    this.knownAgentIds = new Set(initialAgentIds);
422	    this.config = config;
423	  }
424	
425	  /**
426	   * 啟動 subagents 目錄監控（自動偵測新檔案）
427	   */
428	  startDirectoryWatch(): void {
429	    if (!this.config.enabled) return;
430	    if (this.isWatching) return;
431	    if (this.config.watchDir === false) return;
432	
433	    this.isWatching = true;
434	    this.tryWatchSubagentsDir();
435	  }
436	
437	  /**
438	   * 停止所有監控
439	   */
440	  stop(): void {
441	    this.isWatching = false;
442	    this.clearScanTimer();
443	    // 清除所有 pending 的 setTimeout
444	    for (const timer of this.pendingTimers) {
445	      clearTimeout(timer);
446	    }
447	    this.pendingTimers.clear();
448	    this.pendingDescriptions = [];
449	    this.spawnRegistry.clear();
450	    this.dirRetryAttempts = 0;
451	    this.dirWatcher?.close();
452	    this.dirWatcher = null;
453	    this.parentWatcher?.close();
454	    this.parentWatcher = null;
455	  }
456	
457	  /**
458	   * 處理 early subagent detection（Task tool_use 觸發）
459	   * 使用非同步 setTimeout 來避免阻塞主流程
460	   */
461	  handleEarlyDetection(): void {
462	    if (!this.config.enabled) return;
463	
464	    // 延遲掃描（讓檔案有機會建立）
465	    this.schedulePending(EARLY_DETECTION_RETRY.initialDelay, async () => {
466	      try {
467	        const newAgentIds = await scanForNewSubagents(
468	          this.config.subagentsDir,
469	          this.knownAgentIds
470	        );
471	
472	        for (const agentId of newAgentIds) {
473	          this.registerNewAgent(
474	            agentId,
475	            EARLY_DETECTION_RETRY,
476	            `Early subagent detected: ${agentId}`
477	          );
478	        }
479	      } catch (error) {
480	        this.config.output.error(`Early detection scan failed: ${error}`);
481	      }
482	    });
483	  }
484	
485	  /**
486	   * 處理 agent_progress 事件（subagent 進入或 resume 時）
487	   * 只在 resume（已知 agentId）時觸發 onSubagentEnter
488	   * 新 agentId 的 pane 開啟由 onNewSubagent 負責，避免重複觸發
489	   */
490	  handleAgentProgress(agentId: string): void {
491	    if (!this.config.enabled) return;
492	    if (!isValidAgentId(agentId)) return;
493	
494	    // 新 agentId 仍由 early/fallback 路徑完成註冊，避免提前標記 known 造成漏註冊
495	    if (!this.knownAgentIds.has(agentId)) return;
496	
497	    const subagentPath = buildSubagentPath(this.config.subagentsDir, agentId);
498	    this.config.onSubagentEnter?.(agentId, subagentPath);
499	  }
500	
501	  /**
502	   * 處理 fallback detection（toolUseResult 觸發）
503	   * @param agentId - 從 toolUseResult 提取的 agentId
504	   */
505	  handleFallbackDetection(agentId: string): void {
506	    // 驗證 agentId 格式
507	    if (!isValidAgentId(agentId)) {
508	      this.config.output.debug(`Ignoring invalid agentId format: ${agentId}`);
509	      return;
510	    }
511	
512	    // 檢查是否已經監控中
513	    const isAlreadyMonitored = this.knownAgentIds.has(agentId);
514	
515	    if (isAlreadyMonitored) {
516	      // 已經監控中，表示之前透過 early detection 發現過
517	      // 輸出完成訊息，觸發 onSubagentDone（關閉 pane）
518	      this.config.output.warn(`Subagent completed: ${agentId}`);
519	    } else {
520	      // 首次發現且已完成：不開 pane，只註冊監控
521	      this.knownAgentIds.add(agentId);
522	
523	      // Consume pending description to prevent queue drift
524	      // (this agent's Task tool_use pushed a description, but no pane will open)
525	      this.pendingDescriptions.shift();
526	
527	      const subagentPath = buildSubagentPath(this.config.subagentsDir, agentId);
528	
529	      // Session 處理（Interactive 模式）
530	      this.config.session?.addSession?.(
531	        agentId,
532	        makeAgentLabel(agentId),
533	        subagentPath
534	      );
535	
536	      if (this.config.enabled) {
537	        this.config.output.warn(
538	          `New subagent detected (completed): ${agentId}`
539	        );
540	
541	        // 非阻塞式新增檔案監控（但不觸發 onNewSubagent，因為已完成）
542	        // 只在 directory watch 已啟動時才建立 timer，避免孤立 timer 洩漏
543	        if (this.isWatching) {
544	          const timer = setTimeout(() => {
545	            this.pendingTimers.delete(timer);
546	            if (!this.isWatching) return;
547	
548	            tryAddSubagentFile(
549	              subagentPath,
550	              agentId,
551	              this.config.watcher,
552	              this.config.output,
553	              FALLBACK_DETECTION_RETRY
554	            );
555	          }, FALLBACK_DETECTION_RETRY.initialDelay);
556	          this.pendingTimers.add(timer);
557	        }
558	      }
559	    }
560	
561	    // toolUseResult 表示 subagent 已完成
562	    if (this.config.session?.markSessionDone) {
563	      this.config.session.markSessionDone(agentId);
564	      this.config.output.debug(`Subagent completed: ${agentId}`);
565	    }
566	    this.config.session?.updateUI?.();
567	
568	    // 只有已監控的（有開 pane 的）才需要觸發 onSubagentDone
569	    if (isAlreadyMonitored && this.config.hasPane?.(agentId)) {
570	      this.config.onSubagentDone?.(agentId);
571	    }
572	  }
573	
574	  /**
575	   * Push a Task description to the FIFO queue.
576	   * Called when a Task tool_use with description is detected in the main session.
577	   * The description will be matched to the next newly registered agent.
578	   */
579	  pushDescription(description: string): void {
580	    this.pendingDescriptions.push(description);
581	  }
582	
583	  /**
584	   * 記錄一次 Agent tool_use 呼叫的 spawn 關係。
585	   * - toolUseId: Agent tool_use 的 id（例 toolu_01Smf3mRVKSkcMH1p2X1RDxV）
586	   * - parentSource: 呼叫方的 agentId；主 session 請傳 MAIN_SOURCE
587	   *
588	   * Phase 2 用：當新 subagent 註冊且讀到 meta.json 的 toolUseId 時，
589	   * 反查此表得知 parent，組成 [child◂parent] label。
590	   */
591	  recordSpawn(toolUseId: string, parentSource: string): void {
592	    this.spawnRegistry.set(toolUseId, parentSource);
593	  }
594	
595	  /**
596	   * 取得已知的 agentId 集合（供測試使用）
597	   */
598	  getKnownAgentIds(): Set<string> {
599	    return new Set(this.knownAgentIds);
600	  }
601	
602	  /**
603	   * 檢查是否為已知的 agentId
604	   */
605	  isKnownAgent(agentId: string): boolean {
606	    return this.knownAgentIds.has(agentId);
607	  }
608	
609	  private clearScanTimer(): void {
610	    if (this.scanTimer) {
611	      clearTimeout(this.scanTimer);
612	      this.scanTimer = null;
613	    }
614	  }
615	
616	  private scheduleScan(): void {
617	    if (!this.isWatching) return;
618	    this.clearScanTimer();
619	    this.scanTimer = setTimeout(async () => {
620	      if (!this.isWatching) return;
621	      try {
622	        const newAgentIds = await scanForNewSubagents(
623	          this.config.subagentsDir,
624	          this.knownAgentIds
625	        );
626	        for (const agentId of newAgentIds) {
627	          this.registerNewAgent(
628	            agentId,
629	            EARLY_DETECTION_RETRY,
630	            `New subagent detected: ${agentId}`
631	          );
632	        }
633	      } catch (error) {
634	        this.config.output.error(`Directory scan failed: ${error}`);
635	      }
636	    }, 100);
637	  }
638	
639	  private tryWatchSubagentsDir(): void {
640	    if (!this.isWatching) return;
641	
642	    try {
643	      this.parentWatcher?.close();
644	      this.parentWatcher = null;
645	
646	      this.dirWatcher = watch(this.config.subagentsDir, () => {
647	        this.scheduleScan();
648	      });
649	      this.dirWatcher.on('error', () => {
650	        this.dirWatcher?.close();
651	        this.dirWatcher = null;
652	        // 排程 retry，否則 dir 重新出現時無法再 attach
653	        this.scheduleSubagentsDirRetry();
654	      });
655	      // 成功 attach → 重置 retry 計數
656	      this.dirRetryAttempts = 0;
657	      // 目錄建立後先掃描一次，避免錯過已存在的新檔案
658	      this.scheduleScan();
659	    } catch {
660	      // subagents 目錄可能尚未建立，改監控父層目錄
661	      this.watchParentForSubagentsDir();
662	    }
663	  }
664	
665	  private watchParentForSubagentsDir(): void {
666	    if (!this.isWatching) return;
667	    if (this.parentWatcher) return;
668	
669	    const parentDir = join(this.config.subagentsDir, '..');
670	    try {
671	      this.parentWatcher = watch(parentDir, () => {
672	        // 嘗試切回 subagents 目錄監控
673	        this.tryWatchSubagentsDir();
674	      });
675	      this.parentWatcher.on('error', () => {
676	        this.parentWatcher?.close();
677	        this.parentWatcher = null;
678	        // 父層 watcher 掉了，排程 retry（subagentsDir 可能稍後出現）
679	        this.scheduleSubagentsDirRetry();
680	      });
681	    } catch {
682	      // 父層目錄也不存在（典型：session UUID 目錄要等首個 subagent 才被建立）
683	      // 排程 retry，否則 nested subagent 永遠不會被偵測到
684	      this.scheduleSubagentsDirRetry();
685	    }
686	  }
687	
688	  /**
689	   * subagents/ 與其父目錄都不存在時排程 retry（指數退避，上限 30s）。
690	   * Claude Code 在首個 subagent 出現前不會建立 {sessionUUID}/ 目錄；
691	   * agent-tail 若先於首個 subagent 啟動，必須持續 retry 直到目錄出現。
692	   * 對於從不 spawn subagent 的 session，退避避免無止境的 1Hz 輪詢。
693	   */
694	  private scheduleSubagentsDirRetry(): void {
695	    if (!this.isWatching) return;
696	    // 1s, 2s, 4s, 8s, 16s, 30s, 30s...
697	    const delay = Math.min(
698	      SUBAGENTS_DIR_RETRY_DELAY_MS * 2 ** this.dirRetryAttempts,
699	      SUBAGENTS_DIR_RETRY_MAX_DELAY_MS
700	    );
701	    this.dirRetryAttempts++;
702	    this.schedulePending(delay, () => {
703	      if (this.dirWatcher || this.parentWatcher) return; // 同時間其他路徑已 attach
704	      this.tryWatchSubagentsDir();
705	    });
706	  }
707	
708	  /**
709	   * 在 pendingTimers 集合中註冊一個延遲執行的回呼。
710	   * - 自動把 timer 加入 pendingTimers（stop() 會統一清掉）
711	   * - 進入回呼時自動從集合移除
712	   * - 觸發時再次檢查 isWatching，detector 已 stop 則放棄
713	   */
714	  private schedulePending(
715	    delayMs: number,
716	    fn: () => void | Promise<void>
717	  ): void {
718	    if (!this.isWatching) return;
719	    const timer = setTimeout(async () => {
720	      this.pendingTimers.delete(timer);
721	      if (!this.isWatching) return;
722	      await fn();
723	    }, delayMs);
724	    this.pendingTimers.add(timer);
725	  }
726	
727	  private registerNewAgent(
728	    agentId: string,
729	    retryConfig: RetryConfig,
730	    message: string
731	  ): void {
732	    if (this.knownAgentIds.has(agentId)) return;
733	    this.knownAgentIds.add(agentId);
734	
735	    const subagentPath = join(
736	      this.config.subagentsDir,
737	      `agent-${agentId}.jsonl`
738	    );
739	
740	    // 同步先取 FIFO 保持順序；async 部分（meta.json fallback、parent 解析、
741	    // session/watcher 註冊）丟給 finalizeRegistration
742	    const queuedDescription = this.pendingDescriptions.shift();
743	    void this.finalizeRegistration(
744	      agentId,
745	      subagentPath,
746	      queuedDescription,
747	      retryConfig,
748	      message
749	    );
750	  }
751	
752	  /**
753	   * spawnRegistry 反查含 retry：parent JSONL line 與 nested 檔案出現存在 race。
754	   * - 命中 → 從 registry 刪除（每個 toolUseId 只會被 1 個 child consume），
755	   *   MAIN_SOURCE 視為無 parent 回 undefined，其他視為 nested parent。
756	   * - 最多 PARENT_LOOKUP_MAX_ATTEMPTS 次，間隔 PARENT_LOOKUP_DELAY_MS（第 1 次不等）。
757	   */
758	  private async lookupParentWithRetry(
759	    toolUseId: string
760	  ): Promise<string | undefined> {
761	    for (let attempt = 0; attempt < PARENT_LOOKUP_MAX_ATTEMPTS; attempt++) {
762	      const parent = this.spawnRegistry.get(toolUseId);
763	      if (parent) {
764	        this.spawnRegistry.delete(toolUseId);
765	        return parent === MAIN_SOURCE ? undefined : parent;
766	      }
767	      if (attempt < PARENT_LOOKUP_MAX_ATTEMPTS - 1) {
768	        await new Promise((resolve) =>
769	          setTimeout(resolve, PARENT_LOOKUP_DELAY_MS)
770	        );
771	        if (!this.isWatching) return undefined;
772	      }
773	    }
774	    return undefined;
775	  }
776	
777	  /**
778	   * 完成新 subagent 的非同步註冊流程：
779	   * 1. 若 FIFO 沒有 description（典型為 nested subagent）→ 讀 meta.json 補
780	   * 2. 若 meta.json 有 toolUseId → 反查 spawnRegistry 取得 parent agentId
781	   * 3. 用 parent-aware label 註冊 session 與 file watcher
782	   * 4. 觸發 onNewSubagent 回呼
783	   */
784	  private async finalizeRegistration(
785	    agentId: string,
786	    subagentPath: string,
787	    queuedDescription: string | undefined,
788	    retryConfig: RetryConfig,
789	    message: string
790	  ): Promise<void> {
791	    // 一律讀 meta.json：它是 Claude Code 寫的權威來源（description + toolUseId）。
792	    // 不能只在 FIFO 落空時才讀 — FIFO 可能因「歷史 Task 推進去但對應 subagent
793	    // 早已存在、registerNewAgent skip」而累積 stale 條目，後續任何新 subagent
794	    // 註冊都會 shift 到錯誤 description 並跳過 parent lookup。
795	    const meta = await readSubagentMeta(this.config.subagentsDir, agentId);
796	    // detector 已 stop 則放棄（防止跨 session 污染）
797	    if (!this.isWatching) return;
798	
799	    // 偏好 meta.description；FIFO 僅作備援（meta.json 不在或無 description 欄位時）
800	    const description = meta?.description ?? queuedDescription;
801	    let parentAgentId: string | undefined;
802	
803	    if (meta?.toolUseId) {
804	      // Race: parent JSONL 那行 Agent tool_use 可能比 nested 檔出現還晚被
805	      // 解析（→ recordSpawn 後到）。短暫 retry 蓋住典型 50-200ms 窗口；
806	      // 仍查不到就退回無 parent label，不阻塞註冊流程。
807	      parentAgentId = await this.lookupParentWithRetry(meta.toolUseId);
808	      if (!this.isWatching) return;
809	    }
810	
811	    const label = makeAgentLabel(agentId, parentAgentId);
812	
813	    // Session 處理（Interactive 模式）
814	    this.config.session?.addSession?.(agentId, label, subagentPath);
815	
816	    if (!this.config.enabled) return;
817	
818	    // 把 label 帶進 warn 訊息，便於 nested 場景下直接看到 [child◂parent]
819	    const annotatedMessage = parentAgentId ? `${message} ${label}` : message;
820	    this.config.output.warn(annotatedMessage);
821	
822	    // 觸發 onNewSubagent 回呼（pane 自動開啟等用途）
823	    this.config.onNewSubagent?.(agentId, subagentPath, description);
824	
825	    // 非阻塞式新增檔案監控
826	    const timer = setTimeout(() => {
827	      this.pendingTimers.delete(timer);
828	      if (!this.isWatching) return;
829	
830	      tryAddSubagentFile(
831	        subagentPath,
832	        agentId,
833	        this.config.watcher,
834	        this.config.output,
835	        retryConfig,
836	        parentAgentId
837	      );
838	    }, retryConfig.initialDelay);
839	    this.pendingTimers.add(timer);
840	  }
841	}
